import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../context/AuthContext';

export default function StudentProfile() {
  const { user, updateProfile } = useAuth();
  const [form, setForm] = useState({ name: user?.name || '', bio: user?.bio || '' });
  const [saving, setSaving] = useState(false);

  const handleSave = async (e) => {
    e.preventDefault();
    setSaving(true);
    try {
      await updateProfile(form);
      toast.success('Profile updated!');
    } catch { toast.error('Failed to update'); }
    finally { setSaving(false); }
  };

  return (
    <div className="page-wrapper">
      <div className="container" style={{ maxWidth: 620 }}>
        <div className="page-header">
          <div className="flex-between">
            <div>
              <h2 style={{ fontFamily: 'var(--font-display)', marginBottom: 4 }}>MY <span className="gradient-text">PROFILE</span></h2>
              <p style={{ color: 'var(--text-secondary)', fontSize: '0.875rem' }}>Manage your account information</p>
            </div>
            <Link to="/student" className="btn btn-outline">← Dashboard</Link>
          </div>
        </div>

        <div className="card">
          {/* Avatar */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 20, marginBottom: 28, padding: '20px', background: 'var(--bg-elevated)', borderRadius: 'var(--radius-sm)' }}>
            <div className="avatar avatar-xl">{user?.name?.charAt(0)}</div>
            <div>
              <div style={{ fontFamily: 'var(--font-display)', fontSize: '1.5rem' }}>{user?.name}</div>
              <div style={{ fontFamily: 'var(--font-mono)', fontSize: '0.8rem', color: 'var(--cyan-accent)', marginTop: 4 }}>{user?.itNumber}</div>
              <div style={{ display: 'flex', gap: 8, marginTop: 6 }}>
                <span className="badge badge-student">Student</span>
                <span className="badge badge-approved">{user?.status}</span>
              </div>
            </div>
          </div>

          <form onSubmit={handleSave}>
            <div className="form-group">
              <label className="form-label">Full Name</label>
              <input className="form-control" value={form.name} onChange={e => setForm(p => ({ ...p, name: e.target.value }))} required />
            </div>
            <div className="form-group">
              <label className="form-label">Email (read-only)</label>
              <input className="form-control" value={user?.email || ''} disabled style={{ opacity: 0.5 }} />
            </div>
            <div className="form-group">
              <label className="form-label">IT Number (read-only)</label>
              <input className="form-control" value={user?.itNumber || ''} disabled style={{ opacity: 0.5, fontFamily: 'var(--font-mono)' }} />
            </div>
            <div className="form-group">
              <label className="form-label">Bio</label>
              <textarea className="form-control" rows={3} value={form.bio} onChange={e => setForm(p => ({ ...p, bio: e.target.value }))} placeholder="Tell us about yourself..." style={{ resize: 'vertical' }} />
            </div>

            <button type="submit" className="btn btn-primary" style={{ width: '100%', justifyContent: 'center' }} disabled={saving}>
              {saving ? 'Saving...' : 'Save Profile'}
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}
